computed.formula:
const value = String(this.frm_plan_pago || '').trim();
if (!value) return null;

if (['102','105','108'].includes(value)) return 1; // 1 cuota
if (value === '123') return 3;                     // 3 cuotas
return null; // no reconocido

const frm_plan_pago = this.frm_plan_pago;
let cantidad_dias;

switch (frm_plan_pago) {
  case "102":
    cantidad_dias = "30 días";
    break;
  case "105":
    cantidad_dias = "60 días";
    break;
  case "108":
    cantidad_dias = "90 días";
    break;
  case "123":
    cantidad_dias = "90 días";
    break;
  default:
    cantidad_dias = "No definido (dev)";
    break;
}

return cantidad_dias;
